INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the resource name followed by a concise description of what it does. Follow the category-specific pattern. Example: \"Vite — Next-generation frontend build tool\""},"content":{"tips":"Keep it short — this is a directory, not a review. Include the URL, a 2-3 sentence description, key highlights as bullet points, and any important caveats. Focus on why this resource matters."},"formatting":["Bullet lists: key features, highlights, alternatives","Bold: resource name, pricing model, license type","Links: official URL, documentation, GitHub repository","Tables: comparison with alternatives (only when adding multiple related entries)"],"avoid":["Long reviews — keep entries concise and scannable","Missing URLs — every entry must link to the resource","Stale entries without status updates"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":1,"max":3000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

-- Site actions (directory)
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('d4d6a2a6-2b11-4cc1-8837-3d159ddee8db', 'Submit Listing', 'submit-listing', 'Submit a resource for inclusion in the directory', '[{"name":"name","type":"text","label":"Your Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"resource_url","type":"url","label":"Resource URL","required":true,"placeholder":"https://...","maxLength":500},{"name":"description","type":"textarea","label":"Why should this be listed?","required":true,"placeholder":"Describe the resource and why it belongs in the directory...","maxLength":2000}]', '{"success_message":"Thanks for the submission! We''ll review it for inclusion in the directory.","require_honeypot":true}', 'active', '2026-03-27T01:22:46.807Z', '2026-03-27T01:22:46.807Z');
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('f2695f99-25fd-4a57-8307-4733fc270438', 'Report Listing', 'report-listing', 'Report an issue with a listed resource', '[{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"reason","type":"select","label":"Reason","required":true,"options":["Broken Link","Outdated Information","Spam or Inappropriate","Duplicate Entry","Other"]},{"name":"details","type":"textarea","label":"Details","required":true,"placeholder":"Provide additional context about the issue...","maxLength":2000}]', '{"success_message":"Report received! We''ll review the listing and take appropriate action.","require_honeypot":true}', 'active', '2026-03-27T01:22:46.807Z', '2026-03-27T01:22:46.807Z');
